//
// Report of a stacktrace with an aggregated value without timestamps:
//
//	values: [10]
//	 timestamps_unix_nano: []
//
// Report of a stacktrace at 4 timestamps where each point records a specific value:
//
//	values: [2, 2, 3, 3]
//	timestamps_unix_nano: [1, 2, 3, 4]
